#include <bits/stdc++.h>
#define int long long
using namespace std;
int f[205][105];
vector <int> power;
void init () {
	power.push_back (1);
	for (int i = 1; i <= 18; i++) {
		power.push_back (power[power.size() - 1] * 10);
	}
	for (int i = 0; i <= 9; i++) {
		f[1][i] = 1;
	}
	for (int i = 2; i <= 19; i++) {
		for (int j = 0; j <= 9; j++) {
			for (int k = 0; k <= 9; k++) {
				if (abs (j - k) >= 2) {
					f[i][j] += f[i - 1][k];
				}
			}
		}
	}
	return;
}
int solve (int x) {
	int w = 0, y, pre;
	int ans = 0;
	while (w <= 18 && power[w] <= x) {
		w++;
	}
	for (int i = 1; i < w; i++) {
		for (int j = 1; j <= 9; j++) {
			ans += f[i][j];
		}
	}
	y = x / power[w - 1];
	for (int j = 1; j < y; j++) {
		ans += f[w][j];
	}
	pre = y;
	x %= power[w - 1];
	for (int i = w - 1; i >= 1; i--) {
		y = x / power[i - 1];
		for (int j = 0; j < y; j++) {
			if (abs (j - pre) >= 2) {
				ans += f[i][j];
			}
		}
		if (abs (pre - y) < 2) {
			break;
		}
		pre = y;
		x %= power[i - 1];
	}
	return ans;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	int l, r;
	cin >> l >> r;
	init ();
	cout << solve (r + 1) - solve (l);
	return 0;
}
